changeSet.sql:
ALTER TABLE outline_document ADD CONSTRAINT ck_outline_document_tombstone CHECK (
    deleted_at IS NULL OR (
        body_markdown IS NULL AND content_hash IS NULL
        AND created_by_subject IS NULL AND updated_by_subject IS NULL
        AND collaborator_subjects IS NULL
    )
);

CREATE INDEX ix_outline_document_projection ON outline_document
    (workspace_id, deleted_at ASC NULLS FIRST, outline_updated_at DESC NULLS LAST, id ASC);
CREATE INDEX ix_outline_document_eviction ON outline_document
    (workspace_id, last_materialized_at ASC NULLS FIRST) WHERE body_markdown IS NOT NULL;
CREATE INDEX ix_outline_document_slug ON outline_document (workspace_id, slug);

rollback.sql:
DROP INDEX IF EXISTS ix_outline_document_projection;
DROP INDEX IF EXISTS ix_outline_document_eviction;
DROP INDEX IF EXISTS ix_outline_document_slug;
